# Utility module with various features

# Module-level constant
MODULE_VERSION: str = "1.0.0"

# Class with methods
class Calculator:
    @static
    PI: float = 3.14159

    def __init__(self, name: str):
        self.name = name

    def get_display_name(self) -> str:
        return f"Calc: {self.name}"

    def add(self, a: float, b: float) -> float:
        return a + b

    def multiply(self, a: float, b: float) -> float:
        return a * b

    def power(self, base: float, exp: float) -> float:
        result: float = 1.0
        i: int = 0
        while i < int(exp):
            result = result * base
            i = i + 1
        return result

# Helper function
def format_result(value: float, precision: int) -> str:
    if precision == 0:
        return str(int(value))
    elif precision == 1:
        return f"{value:.1f}"
    elif precision == 2:
        return f"{value:.2f}"
    else:
        return f"{value:.3f}"
